import{_ as s,o as t,c as a,a2 as n}from"./chunks/framework.B72_uj9U.js";const h=JSON.parse('{"title":"Beyond Text Search","description":"Why text-based search is insufficient for code understanding and how structural and semantic approaches unlock more powerful agent capabilities.","frontmatter":{"title":"Beyond Text Search","description":"Why text-based search is insufficient for code understanding and how structural and semantic approaches unlock more powerful agent capabilities."},"headers":[],"relativePath":"learn/linear/11-code-intelligence/01-beyond-text-search.md","filePath":"learn/linear/11-code-intelligence/01-beyond-text-search.md"}'),o={name:"learn/linear/11-code-intelligence/01-beyond-text-search.md"};function l(r,e,c,i,p,d){return t(),a("div",null,[...e[0]||(e[0]=[n(`<h1 id="beyond-text-search" tabindex="-1">Beyond Text Search <a class="header-anchor" href="#beyond-text-search" aria-label="Permalink to &quot;Beyond Text Search&quot;">​</a></h1><blockquote><p><strong>What you&#39;ll learn:</strong></p><ul><li>The limitations of text search for code tasks: false positives from comments and strings, inability to understand scope, and lack of type awareness</li><li>How structural search using syntax trees eliminates entire categories of false matches by understanding grammar</li><li>The spectrum from text search to structural search to semantic analysis and when each level is appropriate</li></ul></blockquote><p>Imagine your coding agent receives a request: &quot;Rename the function <code>process_data</code> to <code>transform_data</code> across the codebase.&quot; The naive approach is straightforward — search for the string <code>process_data</code> and replace it everywhere. But within seconds, this falls apart. The string appears in a comment explaining the old API. It appears in a log message: <code>&quot;calling process_data with {} items&quot;</code>. It appears as part of a longer name: <code>process_data_batch</code>. And crucially, there is a completely different <code>process_data</code> function in a test helper module that should not be renamed at all.</p><p>Text search treats source code as a flat sequence of characters. Code is not flat — it has structure, scope, meaning. A coding agent that cannot see that structure is working blindfolded. This subchapter explores why text search breaks down and what the alternatives look like.</p><h2 id="where-text-search-fails" tabindex="-1">Where Text Search Fails <a class="header-anchor" href="#where-text-search-fails" aria-label="Permalink to &quot;Where Text Search Fails&quot;">​</a></h2><p>Let&#39;s start with a concrete example. Suppose you want to find all definitions of a function called <code>connect</code> in a Rust project. A naive grep gives you this:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Here&#39;s what grep &quot;connect&quot; returns:</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// 1. The actual function definition — this is what we want</span></span>
<span class="line"><span style="color:#CBA6F7;">fn</span><span style="color:#89B4FA;font-style:italic;"> connect</span><span style="color:#9399B2;">(</span><span style="color:#EBA0AC;">addr</span><span style="color:#94E2D5;">:</span><span style="color:#94E2D5;"> &amp;</span><span style="color:#F9E2AF;font-style:italic;">str</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#F9E2AF;font-style:italic;">TcpStream</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;"> ...</span><span style="color:#9399B2;"> }</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// 2. A function CALL — not a definition</span></span>
<span class="line"><span style="color:#CBA6F7;">let</span><span style="color:#CDD6F4;"> stream </span><span style="color:#94E2D5;">=</span><span style="color:#89B4FA;font-style:italic;"> connect</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;127.0.0.1:8080&quot;</span><span style="color:#9399B2;">);</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// 3. A comment mentioning the concept</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// TODO: connect to the database before starting the server</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// 4. A string literal</span></span>
<span class="line"><span style="color:#CBA6F7;">let</span><span style="color:#CDD6F4;"> msg </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> &quot;Failed to connect to remote host&quot;</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// 5. A method on a different type entirely</span></span>
<span class="line"><span style="color:#CBA6F7;">impl</span><span style="color:#F9E2AF;font-style:italic;"> WebSocket</span><span style="color:#9399B2;"> {</span></span>
<span class="line"><span style="color:#CBA6F7;">    fn</span><span style="color:#89B4FA;font-style:italic;"> connect</span><span style="color:#9399B2;">(</span><span style="color:#94E2D5;">&amp;</span><span style="color:#F38BA8;">self</span><span style="color:#9399B2;">)</span><span style="color:#94E2D5;"> -&gt;</span><span style="color:#F9E2AF;font-style:italic;"> Result</span><span style="color:#89DCEB;">&lt;</span><span style="color:#9399B2;">()</span><span style="color:#89DCEB;">&gt;</span><span style="color:#9399B2;"> {</span><span style="color:#94E2D5;"> ...</span><span style="color:#9399B2;"> }</span></span>
<span class="line"><span style="color:#9399B2;">}</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// 6. An import statement</span></span>
<span class="line"><span style="color:#CBA6F7;">use</span><span style="color:#CBA6F7;"> crate</span><span style="color:#94E2D5;">::</span><span style="color:#F9E2AF;">network</span><span style="color:#94E2D5;">::</span><span style="color:#CDD6F4;">connect</span><span style="color:#9399B2;">;</span></span></code></pre></div><p>Out of six matches, only two are function definitions (items 1 and 5), and you might only want item 1 if you are looking for the free function. Text search gives you a 33% hit rate at best, and the noise gets worse as codebases grow.</p><p>The problems fall into distinct categories:</p><p><strong>False positives from non-code content.</strong> Comments and string literals are not executable code, but text search cannot tell them apart from real identifiers. In a well-commented codebase, comments might account for 30% or more of matches for common terms.</p><p><strong>No understanding of grammatical role.</strong> The string <code>connect</code> plays different roles depending on where it appears. It is a function definition in one place, a function call in another, a type method somewhere else, and an import in yet another. Text search sees them all as identical byte sequences.</p><p><strong>No scope awareness.</strong> Two functions named <code>connect</code> in different modules are completely separate symbols. Text search merges them into one result set, and any operation on &quot;the <code>connect</code> function&quot; becomes ambiguous.</p><p><strong>No structural boundaries.</strong> Text search cannot answer questions like &quot;find functions that take more than three parameters&quot; or &quot;find all match arms in this function.&quot; These require understanding the tree structure of the code.</p><div class="custom-block python"><p class="custom-block-title">Coming from Python</p><p>Python developers often use <code>ast.parse()</code> from the standard library to get structural understanding:</p><div class="language-python"><button title="Copy Code" class="copy"></button><span class="lang">python</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#CBA6F7;">import</span><span style="color:#CDD6F4;"> ast</span></span>
<span class="line"></span>
<span class="line"><span style="color:#CDD6F4;">source </span><span style="color:#94E2D5;">=</span><span style="color:#FAB387;font-style:italic;"> open</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;">&quot;app.py&quot;</span><span style="color:#9399B2;">).</span><span style="color:#89B4FA;">read</span><span style="color:#9399B2;">()</span></span>
<span class="line"><span style="color:#CDD6F4;">tree </span><span style="color:#94E2D5;">=</span><span style="color:#CDD6F4;"> ast</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">parse</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">source</span><span style="color:#9399B2;">)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;"># Find all function definitions</span></span>
<span class="line"><span style="color:#CBA6F7;">for</span><span style="color:#CDD6F4;"> node </span><span style="color:#CBA6F7;">in</span><span style="color:#CDD6F4;"> ast</span><span style="color:#9399B2;">.</span><span style="color:#89B4FA;">walk</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">tree</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#CBA6F7;">    if</span><span style="color:#FAB387;font-style:italic;"> isinstance</span><span style="color:#9399B2;">(</span><span style="color:#CDD6F4;">node</span><span style="color:#9399B2;">,</span><span style="color:#CDD6F4;"> ast</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">FunctionDef</span><span style="color:#9399B2;">):</span></span>
<span class="line"><span style="color:#FAB387;font-style:italic;">        print</span><span style="color:#9399B2;">(</span><span style="color:#A6E3A1;font-style:italic;">f</span><span style="color:#A6E3A1;">&quot;Function: </span><span style="color:#F5C2E7;">{</span><span style="color:#CDD6F4;">node</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">name</span><span style="color:#F5C2E7;">}</span><span style="color:#A6E3A1;"> at line </span><span style="color:#F5C2E7;">{</span><span style="color:#CDD6F4;">node</span><span style="color:#9399B2;">.</span><span style="color:#CDD6F4;">lineno</span><span style="color:#F5C2E7;">}</span><span style="color:#A6E3A1;">&quot;</span><span style="color:#9399B2;">)</span></span></code></pre></div><p>Rust does not have a built-in multi-language parser. Instead, the ecosystem relies on tree-sitter, which serves the same purpose as <code>ast.parse()</code> but works across dozens of languages with a single, uniform API. If you have used Python&#39;s <code>ast</code> module, the tree-sitter concepts will feel familiar.</p></div><h2 id="the-structural-search-advantage" tabindex="-1">The Structural Search Advantage <a class="header-anchor" href="#the-structural-search-advantage" aria-label="Permalink to &quot;The Structural Search Advantage&quot;">​</a></h2><p>Structural search understands the grammar of the source language. Instead of matching character sequences, it matches patterns in the syntax tree. Here is the same &quot;find function definitions named <code>connect</code>&quot; task using a tree-sitter query:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// Tree-sitter query (S-expression syntax)</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// This matches ONLY function definitions, never calls, comments, or strings</span></span>
<span class="line"><span style="color:#CBA6F7;">let</span><span style="color:#CDD6F4;"> query_source </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> r#&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">    (function_item</span></span>
<span class="line"><span style="color:#A6E3A1;">        name: (identifier) @func_name</span></span>
<span class="line"><span style="color:#A6E3A1;">        (#eq? @func_name &quot;connect&quot;))</span></span>
<span class="line"><span style="color:#A6E3A1;">&quot;#</span><span style="color:#9399B2;">;</span></span></code></pre></div><p>This query says: &quot;Find nodes of type <code>function_item</code> that have a child named <code>name</code> which is an <code>identifier</code> node whose text equals <code>connect</code>.&quot; It will never match a comment, a string literal, or a function call — those are different node types in the syntax tree. The hit rate goes from 33% to 100%.</p><p>Structural search also handles questions that text search simply cannot answer:</p><div class="language-rust"><button title="Copy Code" class="copy"></button><span class="lang">rust</span><pre class="shiki catppuccin-mocha vp-code" tabindex="0"><code><span class="line"><span style="color:#6C7086;font-style:italic;">// &quot;Find all functions that return a Result type&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">let</span><span style="color:#CDD6F4;"> query_source </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> r#&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">    (function_item</span></span>
<span class="line"><span style="color:#A6E3A1;">        name: (identifier) @func_name</span></span>
<span class="line"><span style="color:#A6E3A1;">        return_type: (generic_type</span></span>
<span class="line"><span style="color:#A6E3A1;">            type: (type_identifier) @return_type</span></span>
<span class="line"><span style="color:#A6E3A1;">            (#eq? @return_type &quot;Result&quot;)))</span></span>
<span class="line"><span style="color:#A6E3A1;">&quot;#</span><span style="color:#9399B2;">;</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// &quot;Find all match expressions with more than 5 arms&quot;</span></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// (This requires post-processing the query results to count children)</span></span>
<span class="line"></span>
<span class="line"><span style="color:#6C7086;font-style:italic;">// &quot;Find all struct definitions that derive Debug&quot;</span></span>
<span class="line"><span style="color:#CBA6F7;">let</span><span style="color:#CDD6F4;"> query_source </span><span style="color:#94E2D5;">=</span><span style="color:#A6E3A1;"> r#&quot;</span></span>
<span class="line"><span style="color:#A6E3A1;">    (attribute_item</span></span>
<span class="line"><span style="color:#A6E3A1;">        (attribute</span></span>
<span class="line"><span style="color:#A6E3A1;">            (identifier) @attr_name</span></span>
<span class="line"><span style="color:#A6E3A1;">            (#eq? @attr_name &quot;derive&quot;)</span></span>
<span class="line"><span style="color:#A6E3A1;">            arguments: (token_tree) @derives))</span></span>
<span class="line"><span style="color:#A6E3A1;">    (struct_item</span></span>
<span class="line"><span style="color:#A6E3A1;">        name: (type_identifier) @struct_name)</span></span>
<span class="line"><span style="color:#A6E3A1;">&quot;#</span><span style="color:#9399B2;">;</span></span></code></pre></div><p>None of these queries are possible with text search alone. You could approximate them with regular expressions, but regexes cannot handle nested structures (matching balanced parentheses is the classic example) and quickly become unmaintainable.</p><h2 id="the-code-intelligence-spectrum" tabindex="-1">The Code Intelligence Spectrum <a class="header-anchor" href="#the-code-intelligence-spectrum" aria-label="Permalink to &quot;The Code Intelligence Spectrum&quot;">​</a></h2><p>Code understanding exists on a spectrum, and each level builds on the ones below it:</p><p><strong>Level 1: Text search (grep, ripgrep).</strong> Treats code as plain text. Fast, simple, language-agnostic. Good for finding exact strings, log messages, error codes, and configuration values. Fails when you need to understand what the text <em>means</em> in context.</p><p><strong>Level 2: Structural search (tree-sitter).</strong> Parses code into a syntax tree and matches patterns against the tree structure. Understands node types (function, class, variable), parent-child relationships, and named fields. Cannot resolve cross-file references or understand types beyond what is written in the source.</p><p><strong>Level 3: Semantic analysis (LSP, type checkers).</strong> Understands the full meaning of code — resolved types, cross-file references, trait implementations, generic instantiations. Requires a language-specific analyzer (rust-analyzer, pyright, typescript language server). Slower to set up but provides the deepest understanding.</p><p>A well-designed coding agent uses all three levels, picking the right tool for each task:</p><table tabindex="0"><thead><tr><th>Task</th><th>Best Tool</th><th>Why</th></tr></thead><tbody><tr><td>Find a specific error message</td><td>grep</td><td>Exact text match, no structure needed</td></tr><tr><td>List all functions in a file</td><td>tree-sitter</td><td>Structural query, single-file scope</td></tr><tr><td>Find all callers of a function</td><td>LSP</td><td>Requires cross-file reference resolution</td></tr><tr><td>Search for a TODO comment</td><td>grep</td><td>Text search in comments is appropriate</td></tr><tr><td>Extract function signatures</td><td>tree-sitter</td><td>Structural query on function nodes</td></tr><tr><td>Find the type of a variable</td><td>LSP</td><td>Requires type inference</td></tr></tbody></table><div class="custom-block wild"><p class="custom-block-title">In the Wild</p><p>Claude Code uses a layered approach to code search. Its Grep tool does fast text-level search using ripgrep under the hood, and it respects <code>.gitignore</code> rules to avoid searching generated files and dependencies. For structural understanding, it relies on the LLM&#39;s own ability to parse code from the text it reads — but this comes at the cost of context window tokens. Production agents increasingly integrate tree-sitter to get structural information without consuming prompt tokens on raw source code.</p></div><h2 id="why-this-matters-for-agents" tabindex="-1">Why This Matters for Agents <a class="header-anchor" href="#why-this-matters-for-agents" aria-label="Permalink to &quot;Why This Matters for Agents&quot;">​</a></h2><p>The difference between text search and structural understanding compounds with every tool call. An agent that uses text search to find a function definition might return five candidates. The LLM then needs to read all five, figure out which one is the real definition, and spend tokens disambiguating. An agent with structural search returns exactly one result and moves on.</p><p>Over the course of a complex task — say, refactoring a module — the agent might perform dozens of searches. If each search returns 3x more noise than signal, the agent wastes context window capacity on irrelevant code, risks making changes to the wrong locations, and takes more iterations to complete the task. Structural code intelligence does not just improve accuracy — it improves token efficiency, reduces latency, and lowers the error rate of the entire agent.</p><p>The rest of this chapter teaches you how to build each level of the code intelligence stack. We start with tree-sitter, the workhorse of structural code understanding, then cover high-performance text search with ripgrep, file discovery with glob patterns, and finally the Language Server Protocol for full semantic analysis.</p><h2 id="key-takeaways" tabindex="-1">Key Takeaways <a class="header-anchor" href="#key-takeaways" aria-label="Permalink to &quot;Key Takeaways&quot;">​</a></h2><ul><li>Text search treats code as flat character sequences and cannot distinguish between function definitions, calls, comments, and string literals — leading to high false-positive rates</li><li>Structural search with tree-sitter matches patterns against the syntax tree, eliminating entire categories of false matches by understanding grammatical roles</li><li>Code intelligence exists on a spectrum: text search (fast, imprecise) to structural search (grammar-aware) to semantic analysis (full type and reference resolution)</li><li>A well-designed coding agent uses all three levels, selecting the appropriate tool for each task to balance speed, accuracy, and resource usage</li><li>Structural code intelligence reduces wasted context window tokens, lowers error rates, and decreases the number of iterations needed to complete complex tasks</li></ul>`,35)])])}const y=s(o,[["render",l]]);export{h as __pageData,y as default};
